/* SELECT ' ' AMOUNT_DESCR, 1 AMOUNT, ' ' SUM_INDICATOR, ' ' CALCULATION_FLG FROM DUAL */

SELECT PEN_SICKNESS_DEDUCTIONS_NEW.PERCENTAGE, PEN_SICKNESS_DEDUCTIONS_NEW.EFFECTIVE_DATE FROM pen_dec_fact_types_instance, PEN_SICKNESS_DEDUCTIONS_NEW WHERE pen_dec_fact_types_instance.title_code = '00159' AND pen_dec_fact_types_instance.dec_fact_type_code = '00228' AND pen_dec_fact_types_instance.ins_insured_id = :p_insured_id AND pen_dec_fact_types_instance.DI_DOCUMENT_TYPE_DEC_COCE_SR = '1' AND pen_dec_fact_types_instance.DI_DEC_INCR_SEQ_NO_SR = :P_DEC_INCR_SEC_NO_SR AND pen_dec_fact_types_instance.DI_DECISION_YEAR_SR = :p_dt_decision_year AND pen_dec_fact_types_instance.DI_DEC_UNIT_CODE_SR = :p_dt_dec_unit_code AND pen_dec_fact_types_instance.VALUE = PEN_SICKNESS_DEDUCTIONS_NEW.SICKNESS_DEDUCTION_ID(+) AND :P_ACC_START_DATE >= PEN_SICKNESS_DEDUCTIONS_NEW.EFFECTIVE_DATE AND pen_dec_fact_types_instance.STATUS = '1' UNION SELECT PEN_SICKNESS_DEDUCTIONS_NEW.PERCENTAGE, PEN_SICKNESS_DEDUCTIONS_NEW.EFFECTIVE_DATE FROM pen_dec_fact_types_instance, PEN_SICKNESS_DEDUCTIONS_NEW WHERE pen_dec_fact_types_instance.title_code = '01069' AND pen_dec_fact_types_instance.dec_fact_type_code = '00228' AND pen_dec_fact_types_instance.ins_insured_id = :p_insured_id AND pen_dec_fact_types_instance.DI_DOCUMENT_TYPE_DEC_COCE_SR = '1' AND pen_dec_fact_types_instance.DI_DEC_INCR_SEQ_NO_SR = :P_DEC_INCR_SEC_NO_SR AND pen_dec_fact_types_instance.DI_DECISION_YEAR_SR = :p_dt_decision_year AND pen_dec_fact_types_instance.DI_DEC_UNIT_CODE_SR = :p_dt_dec_unit_code AND pen_dec_fact_types_instance.VALUE = PEN_SICKNESS_DEDUCTIONS_NEW.SICKNESS_DEDUCTION_ID(+) AND :P_ACC_START_DATE >= PEN_SICKNESS_DEDUCTIONS_NEW.EFFECTIVE_DATE AND pen_dec_fact_types_instance.STATUS = '1' UNION SELECT PEN_SICKNESS_DEDUCTIONS_NEW.PERCENTAGE, PEN_SICKNESS_DEDUCTIONS_NEW.EFFECTIVE_DATE FROM pen_dec_fact_types_instance, PEN_SICKNESS_DEDUCTIONS_NEW WHERE pen_dec_fact_types_instance.title_code = '99111' ---EE-DS AND pen_dec_fact_types_instance.dec_fact_type_code = '00228' AND pen_dec_fact_types_instance.ins_insured_id = :p_insured_id AND pen_dec_fact_types_instance.DI_DOCUMENT_TYPE_DEC_COCE_SR = '1' AND pen_dec_fact_types_instance.DI_DEC_INCR_SEQ_NO_SR = :P_DEC_INCR_SEC_NO_SR AND pen_dec_fact_types_instance.DI_DECISION_YEAR_SR = :p_dt_decision_year AND pen_dec_fact_types_instance.DI_DEC_UNIT_CODE_SR = :p_dt_dec_unit_code AND pen_dec_fact_types_instance.VALUE = PEN_SICKNESS_DEDUCTIONS_NEW.SICKNESS_DEDUCTION_ID(+) AND :P_ACC_START_DATE >= PEN_SICKNESS_DEDUCTIONS_NEW.EFFECTIVE_DATE AND pen_dec_fact_types_instance.STATUS = '1' ORDER BY 2 DESC ;
