SELECT 1 
FROM
   PEN_QT_PER_BE_CC_PER_ACCOUNT a
WHERE
   a.ACC_ACCOUNT_NO = :P_ACC_ACCOUNT_NO AND
   a.CP_CALCULATION_PARAMETER_CODE = 'IBBAM';

v_heavy_days VARCHAR2(2);
   
begin
  
  v_heavy_days := null;
  OPEN HEAVY_DAYS;
  FETCH HEAVY_DAYS
  INTO
     v_heavy_days;
  IF HEAVY_DAYS%FOUND THEN
  	 RETURN(1);
  END IF;
  	 
  CLOSE HEAVY_DAYS;
  RETURN (0);

  EXCEPTION
  	WHEN OTHERS THEN
  	   RETURN (0);
end;

