 	 	ELSE
 	 	 V_STRING := 'τη με αριθμό Πρωτοκόλλου '|| :PEN_APPLICATION_INSTANCES_PROT || ' αίτηση περί αναθεώρησης ';
 	 	END IF;	
 	 ELSE
 	 	V_STRING := 'τη με αριθμό Πρωτοκόλλου '|| :PEN_APPLICATION_INSTANCES_PROT || ' αίτηση περί ';
 	 END IF;	
 ELSE 
     V_STRING := 'οίκοθεν την περίπτωση περί ';
