      function CF_21Formula return Number is
V_NUM	  NUMBER;
V_NUM_1	NUMBER;

CURSOR CUR IS
SELECT  ((sum(NVL(MONTH_INCOME_INFLATED,0)+NVL(RETRO_AMT_INFLATED,0))*25)/sum(NVL(MONTH_DAYS,0)))  
FROM PEN_CALC_ADAPOD_RESULTS
WHERE ACCOUNT_NO = :P_ACC_ACCOUNT_NO; 

CURSOR CUR_1 IS
SELECT   NVL(POSOSTO_ANAPL,0)+ NVL(ADAPOD_PERCENT_KSB,0)
FROM  PEN_CALC_ADAPOD_RESULTS
WHERE ACCOUNT_NO = :P_ACC_ACCOUNT_NO;


begin
  
  OPEN CUR;
  FETCH CUR 
  INTO V_NUM;
  CLOSE CUR;
  
  
  OPEN CUR_1;
  FETCH CUR_1 
  INTO V_NUM_1;
  CLOSE CUR_1;
  
  
  RETURN (NVL(V_NUM,0)*NVL(V_NUM_1,0))/100;
  
EXCEPTION
	WHEN OTHERS THEN
	RETURN NULL;
end;

      function CF_29Formula return Number is

V_NUM NUMBER;

CURSOR CUR IS
SELECT ((sum(NVL(MONTH_INCOME_INFLATED,0)+NVL(RETRO_AMT_INFLATED,0))*25)/sum(NVL(MONTH_DAYS,0)))  
FROM PEN_CALC_ADAPOD_RESULTS
WHERE ACCOUNT_NO = :P_ACC_ACCOUNT_NO 
