function AfterPForm return boolean is
CURSOR C1 IS SELECT COM_ORG_BRANCHES.BRANCH_NAME,PEN_PRODUCTS.PRODUCT_CODE FROM REG_INSURED, PEN_APPLICATION_INSTANCES, COM_ORG_BRANCHES, PEN_QC_PER_PRODINST, PEN_PRODUCT_PER_INSTITUTIONS, PEN_PRODUCTS, COM_PENSION_IKA_INSTITUTION WHERE PEN_APPLICATION_INSTANCES.APPLICATION_INCR_SEQ_NO=:P_APPL_INCR_SEQ_NO AND PEN_APPLICATION_INSTANCES.PDTA_APPLICATION_UNIT_CODE=:P_APPL_UNIT_CODE AND PEN_APPLICATION_INSTANCES.PDTA_DOCUMENT_TYPE_APPL_CODE='00001' AND PEN_APPLICATION_INSTANCES.PDTA_APPLICATION_YEAR=:P_APPL_YEAR AND PEN_APPLICATION_INSTANCES.INSURED_ID=:P_INSURED_ID AND REG_INSURED.INSURED_ID=PEN_APPLICATION_INSTANCES.INSURED_ID AND PEN_QC_PER_PRODINST.QC_PER_PRODINST_CODE=:P_QC_PER_PRODINST AND PEN_QC_PER_PRODINST.PRODUCT_PER_INSTITUTION_CODE=PEN_PRODUCT_PER_INSTITUTIONS.PRODUCT_PER_INSTITUTION_CODE AND COM_PENSION_IKA_INSTITUTION.PENSION_IKA_INST_CODE=PEN_PRODUCT_PER_INSTITUTIONS.INSTITUTION_CODE AND PEN_PRODUCTS.PRODUCT_CODE=PEN_PRODUCT_PER_INSTITUTIONS.PRODUCT_CODE AND COM_ORG_BRANCHES.BRANCH_CODE=:P_DT_DEC_UNIT_CODE;
cursor c_wrk is select a.dec_orgbra_code||' / '||a.dec_year||' / '||a.dec_sid from wrk_decisions a where a.status = '1' and a.pen_unit = :P_DT_DEC_UNIT_CODE and a.pen_year = :P_DT_DECISION_YEAR and a.pen_no = :P_DEC_INCR_SEC_NO ; begin OPEN C1; FETCH C1 INTO :P_BRANCH_NAME, :P_PRODUCT_CODE; CLOSE C1;
open c_wrk; fetch c_wrk into :P_WRK_DEC_NO; close c_wrk; -- ΕΡΓΑΣΙΑ ΜΕΤΑ ΤΟ 2024 :P_ERGASIA_2024 := CHECK_ERGASIA_2024(:P_INSURED_ID,:P_DT_DECISION_YEAR,:P_DT_DEC_UNIT_CODE,:P_DEC_INCR_SEC_NO_SR);
return (TRUE); end;

