      function CF_ERGASIAFormula return Char is

cursor cur_synexisi_ergasias is
select count(1) 
from pen_dec_fact_types_instance a
where a.di_document_type_dec_coce_sr = '1'  
and   a.status 			                 = '1'
and   a.ins_insured_id               = :p_insured_id 
and   a.di_dec_incr_seq_no_sr        = :p_dec_incr_sec_no_sr 
and   a.di_decision_year_sr          = :p_dt_decision_year 
and   a.di_dec_unit_code_sr          = :p_dt_dec_unit_code 
and   a.title_code                   in ( '00635','01635' )  --- ΕΡΓΑΣΙΑ (ΑΠΟ 13/05/2016)
and   a.dec_fact_type_code           = '00033'               --- ΣΥΝΕΧΙΣΗ ΕΡΓΑΣΙΑΣ = 1
and   a.value	                       = '1'                   --- 1-YES / 0-NO
;

cursor cur_ergasia is
select decode(a.value	, 'Ε' , 'Το μεικτό ποσό της σύνταξης που δικαιούται ο ασφαλισμένος, ως εργαζόμενος συνταξιούχος, θα πρέπει να μειωθεί '||chr(10)||
			                        'κατά 30% εφόσον για την εργασία / αυτοαπασχόλησή του υπάρχει υποχρέωση υπαγωγής στην ασφάλιση του e-ΕΦΚΑ'
			                , 'ΕΦ', 'Η καταβολή του ποσού της σύνταξης που δικαιούται ο ασφαλισμένος σύμφωνα με την απόφαση αυτή, αναστέλλεται κατά '||chr(10)||
                              'το χρονικό διάστημα που παρέχει εργασία σε Φορέα Γενικής Κυβέρνησης, για την οποία υπάρχει υποχρέωση υπαγωγής '||chr(10)||
                              'στην ασφάλιση του e-ΕΦΚΑ, και μέχρι τη συμπλήρωση του 61ου / 62ου έτους της ηλικίας του, σύμφωνα με τις οικείες '||chr(10)||
                              'διατάξεις του άρθρου 27 του Ν.4670/2020, όπως ισχύει.' ) txt
from pen_dec_fact_types_instance a
where a.di_document_type_dec_coce_sr = '1'  
and   a.status 			                 = '1'
and   a.ins_insured_id               = :p_insured_id 
and   a.di_dec_incr_seq_no_sr        = :p_dec_incr_sec_no_sr 
and   a.di_decision_year_sr          = :p_dt_decision_year 
and   a.di_dec_unit_code_sr          = :p_dt_dec_unit_code 
and   a.title_code                   in ( '00635','01635' )  --- ΕΡΓΑΣΙΑ (ΑΠΟ 13/05/2016)
and   a.dec_fact_type_code           = '00637'               --- ΤΟΜΕΑΣ ΕΡΓΑΣΙΑΣ = 'Ε' / 'ΕΦ' 
and   a.value	                       in ( 'Ε',  'ΕΦ' )       --- EΡΓΑΣΙΑ / ΕΡΓΑΣΙΑ ΣΕ ΦΟΡΕΙΣ ΓΕΝ/ΗΣ ΚΥΒΕΡ  (ΑΠΟ PENLOV_WORK_DOMAIN_EFKA)
union all
select 'Ο ασφαλισμένος εμπίπτει σε μία από τις εξαιρέσεις της παρ. 4 του Ν. 4670/2020, όπως ισχύει, και για το λόγο '||chr(10)||
       'αυτό το ποσό που αναγνωρίζεται με την απόφαση αυτή, παραμένει αμετάβλητο κατά το χρονικό διάστημα '||chr(10)||
       'της εργασίας / αυτοαπασχόλησής τους' txt 
from pen_dec_fact_types_instance a
where a.di_document_type_dec_coce_sr = '1'  
and   a.status 			                 = '1'
and   a.ins_insured_id               = :p_insured_id 
and   a.di_dec_incr_seq_no_sr        = :p_dec_incr_sec_no_sr 
and   a.di_decision_year_sr          = :p_dt_decision_year 
and   a.di_dec_unit_code_sr          = :p_dt_dec_unit_code 
and   a.title_code                   in ( '00635','01635' )   --- ΕΡΓΑΣΙΑ (ΑΠΟ 13/05/2016)
and   a.dec_fact_type_code           = '01676'   --- ΕΞΑΙΡΕΣΕΙΣ ΕΡΓΑΣΙΑΣ ΤΟΥ Ν.4670/2020 (ΑΠΟ PPILOV_WORK_DOMAIN_EXCEPTION)
;

l_synexisi_ergasias number         := 0;
l_cur_ergasia       varchar2(2000) := '';
l_string_out        varchar2(2000) := '';

begin
	
	open  cur_synexisi_ergasias;
	fetch cur_synexisi_ergasias into l_synexisi_ergasias;
	close cur_synexisi_ergasias;

--	SRW.MESSAGE(100,' :l_synexisi_ergasias : '|| l_synexisi_ergasias);
	if nvl(l_synexisi_ergasias,0) > 0 then
		 
		  for x in cur_ergasia
		  loop
		   l_cur_ergasia := x.txt;
		   l_string_out  := l_string_out||chr(10)||l_cur_ergasia||chr(10);
		  end loop; 
		  
		  --SRW.MESSAGE(100,' :P_FACTITIOUS_DATE : '|| :P_FACTITIOUS_DATE);
		  -- το κειμενο για την εργασια εμφανιζεται μονο μετα τις 28/2/2020 που εφαρμοζεται ο ν.4670/2020 και για γηρατος μονο
		  if :P_FACTITIOUS_DATE >= to_date('28/02/2020','dd/mm/yyyy') and :P_PRODUCT_CODE = '00001' then
			  if l_string_out is not null then 
			   :cp_keimeno_ergasias := 'ΕΠΕΙΔΗ Ο ΑΣΦΑΛΙΣΜΕΝΟΣ ΕΧΕΙ ΔΗΛΩΣΕΙ ΟΤΙ ΕΡΓΑΖΕΤΑΙ/ΑΥΤΟΑΠΑΣΧΟΛΕΙΤΑΙ ΚΑΤΑ ΤΗΝ ΗΜΕΡΟΜΗΝΙΑ ΥΠΟΒΟΛΗΣ ΤΗΣ '||chr(10)||
			                           'ΑΙΤΗΣΗΣ ΣΥΝΤΑΞΙΟΔΟΤΗΣΗΣ ΘΑ ΠΡΕΠΕΙ ΝΑ ΕΦΑΡΜΟΣΤΟΥΝ ΟΙ ΔΙΑΤΑΞΕΙΣ ΤΟΥ ΑΡΘΡΟΥ 20 ΤΟΥ Ν.4387/2016, ΟΠΩΣ  '||chr(10)||
			                           'ΤΡΟΠΟΠΟΙΗΘΗΚΕ ΚΑΙ ΙΣΧΥΕΙ ΜΕ ΤΟ ΑΡΘΡΟ 27 ΤΟΥ Ν.4670/2020 ';
			  end if;
		    --SRW.MESSAGE(100,' :cp_keimeno_ergasias : '|| :cp_keimeno_ergasias);
		    return(l_string_out);
		  else
		    return ' ';
		  end if;
  
	else 
	  :cp_keimeno_ergasias := NULL;
		return '';
	
	end if;
		  	
  exception when others then return null;
	
	
end;

      function B_162FormatTrigger return boolean is

begin

  return (TRUE);

end;

      function CF_35Formula return Char is

V_CHAR	VARCHAR2(5);

CURSOR CUR_1 IS
SELECT A.INTRODUCTION_CODE
FROM PEN_PRODUCT_PER_INSTITUTIONS A
,PEN_QC_PER_PRODINST B
WHERE B.PRODUCT_PER_INSTITUTION_CODE=A.PRODUCT_PER_INSTITUTION_CODE
AND B.QC_PER_PRODINST_CODE=:P_QC_PER_PRODINST;

begin
  
 
  OPEN CUR_1;
  FETCH CUR_1 
  INTO V_CHAR;
  CLOSE CUR_1;
  
  
  RETURN V_CHAR;
  
/*EXCEPTION
	WHEN OTHERS THEN
	RETURN NULL;*/
	
end;

