      function M_55FormatTrigger return boolean is
begin
--	srw.message(100, 'ergasia 2024 : '|| :P_ERGASIA_2024); 
  IF :P_ERGASIA_2024 = 0 THEN	 
	 if :cp_keimeno_ergasias is not null
