      function CF_200Formula return Char is
V_DURATION VARCHAR2(50);
V_LHXH	   VARCHAR2(50);  
begin
	
	---- ΠΡΟΣΘΗΚΗ ΑΠΟ 12/7/2021 SPAP ΣΕ ΑΙΤΗΣΗ ΑΠΟ Σ.ΒΑΚΛΑΤΖΗ ΝΑ ΜΗΝ ΕΜΦΑΝΙΖΕΤΑΙ ΤΟ ΚΕΙΜΕΝΟ ΕΑΝ Η ΗΜΝΙΑ ΛΗΞΗΣ ΕΙΝΑΙ ΠΡΟΓΕΝΕΣΤΕΡΗ ΑΠΟ ΤΗΝ ΗΜΝΙΑ ΚΑΤΑΒΟΛΗΣ
	v_LHXH := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,:P_DT_DECISION_YEAR,:P_DT_DEC_UNIT_CODE,:P_DEC_INCR_SEC_NO_SR, '1',
					 0,:p_form_id,'00001','01635','00588');
	
	IF v_LHXH IS NULL THEN
  	v_LHXH := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,:P_DT_DECISION_YEAR,:P_DT_DEC_UNIT_CODE,:P_DEC_INCR_SEC_NO_SR, '1',
					 0,:p_form_id,'00001','00635','00588');
	END IF;
	
	---- ΕΛΕΓΧΟΣ ΕΙΔΙΚΗΣ ΠΛΗΡΟΦΟΡΙΑΣ ΕΡΓΑΣΙΑΣ 
  v_DURATION := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,:P_DT_DECISION_YEAR,:P_DT_DEC_UNIT_CODE,:P_DEC_INCR_SEC_NO_SR, '1',
					 0,:p_form_id,'00001','01635','00637');
	
	IF V_DURATION IS NULL THEN
  	v_DURATION := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,:P_DT_DECISION_YEAR,:P_DT_DEC_UNIT_CODE,:P_DEC_INCR_SEC_NO_SR, '1',
					 0,:p_form_id,'00001','00635','00637');
	END IF;


  
  IF TO_DATE(v_LHXH,'DD/MM/YYYY') < :P_PAYMENT_START_DATE THEN
  	RETURN '' ;
  ELSE  
    --COMBAT_dEBUGING('v_DURATION = '||v_DURATION, 'CHRYS_REPORTS');
    return v_DURATION;
  END IF;
  
  RETURN '';
END;
